use std::collections::HashMap;
use std::fs::{self, File};
use std::io::{self, Read};
use std::path::{Path, PathBuf};

struct SiteState {
    content_cache: HashMap<String, String>,
    last_modified: HashMap<String, std::time::SystemTime>,
}
impl Default for SiteState {
    fn default() -> Self {
        SiteState {
            content_cache: HashMap::new(),
            last_modified: HashMap::new(),
        }
    }
}

fn process_directory(root_path: &Path) -> io::Result<SiteState> {
    let mut state = SiteState::default();
    let entries = fs::read_dir(root_path).map_err(|e| io::Error::new(io::ErrorKind::NotFound, e))?;

    for entry in entries {
        let entry = entry.map_err(|e| io::Error::new(io::ErrorKind::Other, e))?;
        let path = entry.path();
        if path.is_file() && path.extension().map_or(false, |ext| ext == "md") {
            let relative_path = root_path.join(&path).strip_prefix(root_path).unwrap().to_string_lossy().to_string();
            println!("Processing file: {}", relative_path);

            let mut file = File::open(&path).map_err(|e| io::Error::new(io::ErrorKind::Other, e))?;
            let mut buffer = String::new();
            file.read_to_string(&mut buffer).map_err(|e| io::Error::new(io::ErrorKind::Other, e))?;

            let metadata = fs::metadata(&path).map_err(|e| io::Error::new(io::ErrorKind::Other, e))?;
            let modified = metadata.modified().map_err(|e| io::Error::new(io::ErrorKind::Other, e))?;

            state.content_cache.insert(relative_path.clone(), buffer);
            state.last_modified.insert(relative_path, modified);
        }
    }
    Ok(state)
}

fn main() -> io::Result<()> {
    let root = Path::new("./content");
    if !root.exists() {
        println!("Please create a 'content' directory with markdown files to test.");
        return Ok(());
    }

    let initial_state = process_directory(root)?;

    println!("n--- Initial Build Complete ---");
    for (key, _content) in &initial_state.content_cache {
        println!("Cached: {}", key);
    }

    Ok(())
}

use std::fs;
use std::thread;
use std::time::Duration;
fn main() -> std::io::Result<()> {
    let paths = vec![
        "/etc/passwd".to_string(),
        "/tmp".to_string(),
        "Cargo.toml".to_string(),
    ];
    let mut handles = Vec::new();

    for path in paths {
        let path_clone = path;
        let handle = thread::spawn(move || -> std::io::Result<()> {
            loop {
                match fs::metadata(&path_clone) {
                    Ok(metadata) => {
                        println!("File: {}	Size: {} bytes", path_clone, metadata.len());
                    }
                    Err(e) => {
                        eprintln!("Could not read metadata for {}: {}", path_clone, e);
                    }
                }
                thread::sleep(Duration::from_secs(3));
            }
        });
        handles.push(handle);
    }

    for handle in handles {
        let _ = handle.join();
    }
    Ok(())
}

use std::fs;
use std::io::{self, Read};
use std::path::{Path, PathBuf};

fn walk_directory(current_path: &Path) -> io::Result<Vec<PathBuf>> {
    let mut found_paths = Vec::new();
    if !current_path.exists() || !current_path.is_dir() {
        return Ok(found_paths);
    }

    for entry in fs::read_dir(current_path)? {
        let entry = entry?;
        let path = entry.path();
        if path.is_dir() {
            match walk_directory(&path) {
                Ok(mut sub_paths) => found_paths.append(&mut sub_paths),
                Err(e) => eprintln!("Error reading directory {:?}: {}", path, e),
            }
        } else {
            found_paths.push(path);
        }
    }
    Ok(found_paths)
}

fn main() -> io::Result<()> {
    let start_dir = PathBuf::from(".");
    println!("Starting recursive search in: {:?}", start_dir.canonicalize()?);

    let all_files = walk_directory(&start_dir)?;

    if all_files.is_empty() {
        println!("No files found.");
        return Ok(());
    }

    println!("
Found {} potential items.", all_files.len());

    for file_path in all_files {
        match fs::metadata(&file_path) {
            Ok(metadata) => {
                if metadata.is_file() {
                    let mut buffer = Vec::new();
                    match fs::File::open(&file_path) {
                        Ok(mut file) => {
                            if let Err(e) = file.read_to_end(&mut buffer) {
                                eprintln!("Error reading file {:?}: {}", file_path, e);
                            } else {
                                print!("Successfully processed file: {:?}", file_path);
                            }
                        }
                        Err(e) => eprintln!("Could not open file {:?}: {}", file_path, e),
                    }
                }
            }
            Err(e) => eprintln!("Metadata error for {:?}: {}", file_path, e),
        }
    }

    Ok(())
}

use std::collections::VecDeque;

struct PluginState {
    data: VecDeque<u32>,
}

impl PluginState {
    fn new(initial_data: &[u32]) -> Self {
        PluginState {
            data: initial_data.iter().cloned().collect(),
        }
    }

    fn check_integrity(&self) -> u32 {
        self.data.iter().fold(0u32, |acc, &x| acc.wrapping_add(x % 10)) * 2
    }

    fn process_cycle(&mut self) -> Option<u32> {
        if self.data.is_empty() {
            return None;
        }
        let head = *self.data.front().unwrap();
        self.data.pop_front();
        Some(head)
    }
}

fn main() {
    let initial_set = vec![10, 20, 30];
    let mut state = PluginState::new(&initial_set);

    println!("Initial Check: {}", state.check_integrity());

    let mut cycle_count = 3;
    loop {
        if cycle_count == 0 {
            break;
        }
        match state.process_cycle() {
            Some(val) => println!("Cycle processing value: {}", val),
            None => break,
        }
        cycle_count -= 1;
    }

    println!("Final Check after cycles: {}", state.check_integrity());
}

use std::collections::VecDeque;

struct RollingStats {
    data_window: VecDeque<f64>,
    sum: f64,
    count: usize,
}

impl RollingStats {
    fn new() -> Self {
        RollingStats {
            data_window: VecDeque::new(),
            sum: 0.0,
            count: 0,
        }
    }

    fn add_reading(&mut self, reading: f64) -> Option<f64> {
        const WINDOW_SIZE: usize = 10;
        if self.data_window.len() == WINDOW_SIZE {
            let oldest = self.data_window.pop_front().unwrap();
            self.sum -= oldest;
        }
        self.data_window.push_back(reading);
        self.sum += reading;
        self.count = self.data_window.len();

        if self.count < 1 {
            return None;
        }

        let mean = self.sum / (self.count as f64);
        Some(mean)
    }
}

fn main() {
    let mut stats_calculator = RollingStats::new();
    let readings = vec![10.0, 12.0, 8.0, 15.0, 9.0, 11.0, 7.0, 13.0, 6.0, 14.0, 10.5];

    let results: Vec<Option<f64>> = readings.into_iter().map(|r| {
        stats_calculator.add_reading(r)
    }).collect();

    for (i, result) in results.iter().enumerate() {
        if let Some(mean) = result {
            println!("After reading {}: Mean is {:.2}", i + 1, mean);
        }
    }
}
